def test_tc_abs_007_synchronous_update(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_ABS_WHEEL_INFO, 1)
    for msg in msgs:
        speeds = [decode_fl_speed(msg), decode_fr_speed(msg), decode_rl_speed(msg), decode_rr_speed(msg)]
        assert max(speeds) - min(speeds) <= 5
